import{_ as r,C as d,o as l,c as s,j as t,a as o,E as i,a3 as n}from"./chunks/framework.D3_W51PR.js";const T=JSON.parse('{"title":"Shell Tab Completion","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/shell-completion.md","filePath":"advanced/shell-completion.md"}'),c={name:"advanced/shell-completion.md"},h={id:"shell-tab-completion",tabindex:"-1"};function p(m,e,u,g,b,f){const a=d("VersionBadge");return l(),s("div",null,[t("h1",h,[e[0]||(e[0]=o("Shell Tab Completion ",-1)),i(a,{v:"0.10.0"}),e[1]||(e[1]=o()),e[2]||(e[2]=t("a",{class:"header-anchor",href:"#shell-tab-completion","aria-label":'Permalink to "Shell Tab Completion <VersionBadge v="0.10.0" />"'},"​",-1))]),e[3]||(e[3]=n('<p>amoxide completes profile names, alias names, subcommand-alias segments, and variable names at the tab key — anywhere you&#39;d type them.</p><h2 id="what-completes-where" tabindex="-1">What completes where <a class="header-anchor" href="#what-completes-where" aria-label="Permalink to &quot;What completes where&quot;">​</a></h2><table tabindex="0"><thead><tr><th>You type</th><th>Tab gives you</th></tr></thead><tbody><tr><td><code>am use &lt;TAB&gt;</code></td><td>active and inactive profile names</td></tr><tr><td><code>am profile use &lt;TAB&gt;</code>, <code>am profile remove &lt;TAB&gt;</code></td><td>profile names</td></tr><tr><td><code>am remove &lt;TAB&gt;</code></td><td>alias names from the current context (global + active profiles + project)</td></tr><tr><td><code>am remove -p rust &lt;TAB&gt;</code></td><td>aliases from the <code>rust</code> profile only</td></tr><tr><td><code>am remove -g &lt;TAB&gt;</code></td><td>global aliases only</td></tr><tr><td><code>am remove -l &lt;TAB&gt;</code></td><td>project (local) aliases only</td></tr><tr><td><code>am remove jj&lt;TAB&gt;</code></td><td>subcommand-alias keys starting with <code>jj</code> (e.g. <code>jj:ab</code>, <code>jj:b:l</code>)</td></tr><tr><td><code>am remove jj:b&lt;TAB&gt;</code></td><td>colon-narrowed: keys under <code>jj:b:*</code> (e.g. <code>jj:b:l</code>, <code>jj:b:n</code>) — works in fish/zsh; bash needs <code>:</code> out of <code>COMP_WORDBREAKS</code></td></tr><tr><td><code>am remove jj --sub &lt;TAB&gt;</code></td><td>the next segment of a subcommand-alias chain (e.g. <code>b</code>, <code>ab</code>) — same target, longhand</td></tr><tr><td><code>am var get &lt;TAB&gt;</code>, <code>am var unset &lt;TAB&gt;</code></td><td>variable names from the current context, scoped by <code>-p</code> / <code>-l</code> / <code>-g</code></td></tr><tr><td><code>am export -p &lt;TAB&gt;</code>, <code>am import -p &lt;TAB&gt;</code>, <code>am share -p &lt;TAB&gt;</code></td><td>profile names</td></tr></tbody></table><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p><code>am init &lt;shell&gt;</code> includes a one-line registration that wires amoxide into your shell&#39;s completion system. When you hit tab, the shell calls back into <code>am</code> to ask what&#39;s valid in the current spot. The lookup runs against your live config, so completions stay accurate without any cache to invalidate.</p><p>Nothing extra to install or source. If you&#39;ve already run <code>am setup</code>, completion turns on the next time you open a shell.</p><h2 id="supported-shells" tabindex="-1">Supported shells <a class="header-anchor" href="#supported-shells" aria-label="Permalink to &quot;Supported shells&quot;">​</a></h2><ul><li><strong>Bash</strong> (3.2+)</li><li><strong>Zsh</strong></li><li><strong>Fish</strong></li><li><strong>PowerShell</strong> (5.1 + 7)</li><li><strong>Brush</strong> — rides the bash shim</li></ul><p>Nushell isn&#39;t supported yet; upstream tracking is in <a href="https://github.com/clap-rs/clap/pull/5841" target="_blank" rel="noreferrer"><code>clap-rs/clap#5841</code></a>.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="completion-stopped-working-after-upgrade" tabindex="-1">Completion stopped working after upgrade <a class="header-anchor" href="#completion-stopped-working-after-upgrade" aria-label="Permalink to &quot;Completion stopped working after upgrade&quot;">​</a></h3><p>Open a new shell, or re-run <code>eval &quot;$(am init &lt;shell&gt;)&quot;</code> in your current session. The <code>am init</code> output carries the completion registration; old shells won&#39;t have it until they re-evaluate it.</p><h3 id="registration-is-there-but-tab-does-nothing" tabindex="-1">Registration is there but tab does nothing <a class="header-anchor" href="#registration-is-there-but-tab-does-nothing" aria-label="Permalink to &quot;Registration is there but tab does nothing&quot;">​</a></h3><p>Check your shell version (bash ≥ 3.2, zsh, fish, powershell 5.1+). For bash, make sure no stray <code>complete -F</code> from another tool overrides amoxide&#39;s. The <code>bash-completion</code> package isn&#39;t required.</p>',14))])}const k=r(c,[["render",p]]);export{T as __pageData,k as default};
